<template>
  <div class="block" :id="title" v-on:click="changeRouter(routeName)">
    <i :class="icon"></i><span class="text">{{ title }}</span>
  </div>
</template>

<script>
import "scroll-into-view";
var scrollIntoView = require("scroll-into-view");
export default {
  name: "Block",
  props: {
    title: String,
    icon: String,
    routeName: String,
  },
  data() {
    return {};
  },
  methods: {
    changeRouter(routeName) {
      let newPath = "/" + routeName;
      let oldPath = this.$route.path;
      const block = document.getElementById(
        routeName.charAt(0).toUpperCase() + routeName.slice(1)
      );
      scrollIntoView(block, { align: { top: 0 } });
      if (oldPath != newPath) {
        this.$router.push(newPath);
      }
    },
  },
};
</script>

<style scoped>
* {
  padding: 0;
  margin: 0;
}
.block {
  display: inline-block;
  min-width: 15vh;
  height: 10vh;
  line-height: 10vh;
  font-family: "Helvetica Neue", Helvetica, "PingFang SC", "Hiragino Sans GB",
    "Microsoft YaHei", "微软雅黑", Arial, sans-serif;
  font-size: 2vw;
  color: #fe510d;
  background-color: #343130;
  transition: all 0.2s ease-in-out;
  border-radius: 10px;
  margin-right: 10px;
  margin-top: 2.5vh;
  text-align: center;
}
.block:hover {
  width: 25vh;
  cursor: pointer;
  background-color: #fe510d;
  color: #f0f0f0;
}

.block:hover .text {
  display: inline-block;
}
.text {
  display: none;
  font-size: 1vw;
  margin-left: 10px;
  color: #f0f0f0;
  font-family: "Helvetica Neue", Helvetica, "PingFang SC", "Hiragino Sans GB",
    "Microsoft YaHei", "微软雅黑", Arial, sans-serif;
}
</style>
