<script>
import Block from "@/components/Block.vue";
import { loadFile } from "./utils/utils.js";
export default {
  components: { Block },
  data() {
    return {
      imgs: [
        "",
        {
          url: require("../src/assets/img1.png"),
          out_link: "https://doi.org/10.1016/j.patcog.2023.109833",
        },
        {
          url: require("../src/assets/img2.png"),
          out_link:
            "https://github.com/Marigoldwu/A-Unified-Framework-for-Deep-Attribute-Graph-Clustering",
        },
        {
          url: require("../src/assets/img3.png"),
          out_link: "https://www.marigold.website",
        },
      ],
      loadedImages: 0, // 记录已加载的图片数量
      citations: 0,
      followers: 0,
      loading: true,
    };
  },
  mounted() {
    const file = loadFile("data.json");
    let data = JSON.parse(file);
    this.citations = data.citations;
    this.followers = data.followers;
    this.$nextTick(() => {
      this.$refs.reNum.start();
    });
    document.addEventListener("DOMContentLoaded", function () {
      const blocks = document.querySelectorAll(".block");
      console.log(blocks);

      blocks.forEach((block) => {
        block.addEventListener("click", function () {
          // Remove "selected" class from all blocks
          blocks.forEach((otherBlock) => {
            otherBlock.classList.remove("selected");
          });

          // Add "selected" class to the clicked block
          block.classList.add("selected");
        });
      });
    });
  },
  methods: {
    onImageLoad() {
      this.loadedImages++;
      // 检查是否所有图片都加载完成
      if (this.loadedImages == 3) {
        this.loading = false; // 所有图片加载完成后，设置loading为false
      }
    },
  },
};
</script>


